import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";

export function Login() {
  const [email, setEmail] = useState("");
  const [lozinkaHash, setLozinka] = useState("");
  const imeRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

  const handleSubmit = async (e, role) => {
    e.preventDefault();
    if (!email || !lozinkaHash) {
      alert("Molimo unesite email i lozinku!");
      return;
    }

    try {
      const url =
        role === "admin"
          ? `http://localhost:8080/receptionists/login/${email}/${lozinkaHash}`
          : `http://localhost:8080/guests/login/${email}/${lozinkaHash}`;

      const response = await fetch(url, { method: "GET" });

      if (response.ok) {
        const data = await response.json();

        if (role === "gost") {
          const guest = data.data.guest;

          // Čuvanje u cookie: email i id
          document.cookie = `userEmail=${guest.email}; path=/;`;
          document.cookie = `userId=${guest.idGost}; path=/;`;

          navigate("/gosti"); // redirekcija
        } else {
          const receptionist = data.data.receptionist;

          // Čuvanje u cookie: email i id
          document.cookie = `userEmail=${receptionist.korisnickoIme}; path=/;`;
          document.cookie = `userId=${receptionist.idRecepcionar}; path=/;`;

          navigate("/recepcionar"); // redirekcija
        }
      } else {
        alert("Pogrešno uneti podaci!");
      }
    } catch (error) {
      console.error("Greška prilikom login-a:", error);
      alert("Server nije dostupan.");
    }
  };

  return (
    <>
      <NavBar />
      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "column",
        }}
      >
        <div
          className="forma"
          style={{
            width: "300px",
            height: "300px",
            padding: "30px",
            display: "flex",
            justifyContent: "center",
            flexDirection: "column",
          }}
        >
          <form>
            <span className="formaSpan">
              Unesite email
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                ref={imeRef}
                required
              />
            </span>

            <span className="formaSpan">
              Unesite lozinku
              <input
                type="password"
                value={lozinkaHash}
                onChange={(e) => setLozinka(e.target.value)}
                required
              />
            </span>

            <div
              style={{
                display: "flex",
                justifyContent: "center",
                gap: "15px",
                marginTop: "20px",
                marginLeft: "15px",
              }}
            >
              <button
                onClick={(e) => handleSubmit(e, "gost")}
                type="button"
                className="btnNav"
                style={{
                  flex: 1,
                  border: "none",
                  fontSize: "18px",
                  width: "160px",
                  height: "50px",
                }}
              >
                Uloguj se
              </button>

              <button
                onClick={(e) => handleSubmit(e, "admin")}
                type="button"
                className="btnNav"
                style={{
                  flex: 1,
                  border: "none",
                  fontSize: "18px",
                  width: "160px",
                  height: "50px",
                }}
              >
                Uloguj se kao recepcionar
              </button>
            </div>
          </form>
        </div>
      </div>
      <Footer />
    </>
  );
}
